j:jelly.g:evaluate:

var api = new MttrDashboardAPI();
var r = api.getPatchedMTTR();
r ? JSON.stringify(r) : '';

j:jelly.script:
// IIFE scope-guard — see mttr_widget_team_casetype.xml for full
// rationale (sibling widgets declare _scheduleRedraw / drawChart /
// noData at top level; the wrap keeps them per-widget-scoped).
(function () {
    google.charts.load('current', { packages: ['corechart'] });
    google.charts.setOnLoadCallback(function() { setTimeout(drawChart, 100); });

    var _rtimer = null;
    function _scheduleRedraw() {
        if (_rtimer) clearTimeout(_rtimer);
        _rtimer = setTimeout(drawChart, 150);
    }
    // Idempotent listener setup — see mttr_widget_hist_inc_priority.xml
    // for the rationale (SN re-renders re-run this script; naive
    // addEventListener leaks a handler on every mount).
    if (window.__mttrPatchedState) {
        window.removeEventListener('resize', window.__mttrPatchedState.resizeHandler);
        if (window.__mttrPatchedState.observer) {
            window.__mttrPatchedState.observer.disconnect();
        }
    }
    window.addEventListener('resize', _scheduleRedraw);
    var _obsPatched = null;
    if (typeof ResizeObserver !== 'undefined') {
        _obsPatched = new ResizeObserver(_scheduleRedraw);
        _obsPatched.observe(document.getElementById('chart_patched'));
    }
    window.__mttrPatchedState = { resizeHandler: _scheduleRedraw, observer: _obsPatched };

    function drawChart() {
        try {
            var _el = document.getElementById('chart_patched');
            var _w = _el.offsetWidth;
            if (_w > 0) {
                _el.style.height = Math.max(220, Math.round(_w * 0.75)) + 'px';
            }
            var raw = document.getElementById('mttr_data_patched').value;
            if (!raw || raw === 'null') { noData(); return; }
            var allData = JSON.parse(raw);
            var d = allData.patched;
            if (!d) { noData(); return; }

            var incH = d.incident_hours || 0;
            var qryH = d.query_hours || 0;
            if (incH + qryH === 0) { noData(); return; }

            var rows = [['Case Type', 'MTTR (Days)', { role: 'tooltip' }]];
            if (qryH > 0)
                rows.push(['Query = ' + (d.Query || ''), Math.round((qryH / 24) * 10) / 10, 'Query: ' + (d.Query || '')]);
            if (incH > 0)
                rows.push(['Incident = ' + (d.Incident || ''), Math.round((incH / 24) * 10) / 10, 'Incident: ' + (d.Incident || '')]);

            var data = google.visualization.arrayToDataTable(rows);
            var chart = new google.visualization.PieChart(
                document.getElementById('chart_patched'));
            chart.draw(data, {
                pieHole: 0.35,
                chartArea: { width: '85%', height: '85%' },
                legend: { position: 'bottom', textStyle: { fontSize: 11 } },
                colors: ['#3498db', '#e74c3c'],
                backgroundColor: 'transparent',
                pieSliceText: 'none',
                tooltip: { textStyle: { fontSize: 12 } }
            });
        } catch (e) {
            console.error('mttr_widget_patched error:', e);
            noData();
        }
    }

    function noData() {
        // DOM-API placeholder — see mttr_widget_team_trend.xml for
        // the full rationale (escaped-entity innerHTML rendered as
        // literal text; createElement produces a real p node).
        var container = document.getElementById('chart_patched');
        container.innerHTML = '';
        var p = document.createElement('p');
        p.style.color = '#999';
        p.style.textAlign = 'center';
        p.style.padding = '40px';
        p.textContent = 'No data available';
        container.appendChild(p);
    }
})();
